const _ = require('lodash');
const data = require('../../data/problems.json');

/**
 * Service to handle problems data with filtering, pagination and metadata.
 */
class ProblemsService {
  /**
   * List problems with optional filters and metadata including component language and status totals.
   * @param {Object} params - Parameters for filtering and pagination
   * @param {boolean} params.includeComponents - Whether to include component language and status totals metadata
   * @param {number} [params.limit] - Maximum number of problems to return
   * @param {string[]} [params.tags] - Tags to filter problems by
   * @param {string[]} [params.difficulties] - Difficulties to filter problems by
   * @returns {Object} - Object containing filtered problems and metadata
   */
  static listProblems(params) {
    const {
      includeComponents = false,
      limit,
      tags = [],
      difficulties = []
    } = params || {};

    // Filter problems by tags and difficulties
    let filtered = data;

    if (tags.length > 0) {
      filtered = filtered.filter(problem => {
        if (!problem.tags) return false;
        return tags.every(tag => problem.tags.includes(tag));
      });
    }

    if (difficulties.length > 0) {
      filtered = filtered.filter(problem => difficulties.includes(problem.difficulty));
    }

    // Apply limit if specified
    let limited = filtered;
    if (typeof limit === 'number' && limit >= 0) {
      limited = filtered.slice(0, limit);
    }

    // Prepare metadata
    const metadata = {};

    if (includeComponents) {
      // Compute componentLanguageTotals and componentStatusTotals for the limited set
      const componentLanguageTotals = {};
      const componentStatusTotals = {};

      limited.forEach(problem => {
        if (problem.components && Array.isArray(problem.components)) {
          problem.components.forEach(component => {
            // Language totals
            if (component.language) {
              componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
            }
            // Status totals
            if (component.status) {
              componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
            }
          });
        }
      });

      metadata.componentLanguageTotals = componentLanguageTotals;
      metadata.componentStatusTotals = componentStatusTotals;
    }

    return {
      problems: limited,
      metadata
    };
  }
}

module.exports = ProblemsService;
